(window.webpackJsonp=window.webpackJsonp||[]).push([[464],{759:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">maxSize</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> CustomStack = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">maxSize</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.stack=[]\\n  <span class=\\"hljs-keyword\\">this</span>.limit=maxSize\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} x\\n * @return {void}\\n */</span>\\nCustomStack.prototype.push = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">x</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stack.length&lt;<span class=\\"hljs-keyword\\">this</span>.limit)<span class=\\"hljs-keyword\\">this</span>.stack.push(x)\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * @return {number}\\n */</span>\\nCustomStack.prototype.pop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stack.length===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.stack.pop()\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} k \\n * @param {number} val\\n * @return {void}\\n */</span>\\nCustomStack.prototype.increment = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">k, val</span>) </span>{\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;k;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(i&gt;=<span class=\\"hljs-keyword\\">this</span>.stack.length)<span class=\\"hljs-keyword\\">break</span>\\n    <span class=\\"hljs-keyword\\">this</span>.stack[i]+=val\\n  }\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Your CustomStack object will be instantiated and called as such:\\n * var obj = new CustomStack(maxSize)\\n * obj.push(x)\\n * var param_2 = obj.pop()\\n * obj.increment(k,val)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"design-a-stack-with-increment-operation","hasThinking":false,"content":"<p>\u8bf7\u4f60\u8bbe\u8ba1\u4e00\u4e2a\u652f\u6301\u4e0b\u8ff0\u64cd\u4f5c\u7684\u6808\u3002</p>\\n\\n<p>\u5b9e\u73b0\u81ea\u5b9a\u4e49\u6808\u7c7b <code>CustomStack</code> \uff1a</p>\\n\\n<ul>\\n\\t<li><code>CustomStack(int maxSize)</code>\uff1a\u7528 <code>maxSize</code> \u521d\u59cb\u5316\u5bf9\u8c61\uff0c<code>maxSize</code> \u662f\u6808\u4e2d\u6700\u591a\u80fd\u5bb9\u7eb3\u7684\u5143\u7d20\u6570\u91cf\uff0c\u6808\u5728\u589e\u957f\u5230 <code>maxSize</code> \u4e4b\u540e\u5219\u4e0d\u652f\u6301 <code>push</code> \u64cd\u4f5c\u3002</li>\\n\\t<li><code>void push(int x)</code>\uff1a\u5982\u679c\u6808\u8fd8\u672a\u589e\u957f\u5230 <code>maxSize</code> \uff0c\u5c31\u5c06 <code>x</code> \u6dfb\u52a0\u5230\u6808\u9876\u3002</li>\\n\\t<li><code>int pop()</code>\uff1a\u5f39\u51fa\u6808\u9876\u5143\u7d20\uff0c\u5e76\u8fd4\u56de\u6808\u9876\u7684\u503c\uff0c\u6216\u6808\u4e3a\u7a7a\u65f6\u8fd4\u56de <strong>-1</strong> \u3002</li>\\n\\t<li><code>void inc(int k, int val)</code>\uff1a\u6808\u5e95\u7684 <code>k</code> \u4e2a\u5143\u7d20\u7684\u503c\u90fd\u589e\u52a0 <code>val</code> \u3002\u5982\u679c\u6808\u4e2d\u5143\u7d20\u603b\u6570\u5c0f\u4e8e <code>k</code> \uff0c\u5219\u6808\u4e2d\u7684\u6240\u6709\u5143\u7d20\u90fd\u589e\u52a0 <code>val</code> \u3002</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>\\n[&quot;CustomStack&quot;,&quot;push&quot;,&quot;push&quot;,&quot;pop&quot;,&quot;push&quot;,&quot;push&quot;,&quot;push&quot;,&quot;increment&quot;,&quot;increment&quot;,&quot;pop&quot;,&quot;pop&quot;,&quot;pop&quot;,&quot;pop&quot;]\\n[[3],[1],[2],[],[2],[3],[4],[5,100],[2,100],[],[],[],[]]\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null,null,null,2,null,null,null,null,null,103,202,201,-1]\\n<strong>\u89e3\u91ca\uff1a</strong>\\nCustomStack customStack = new CustomStack(3); // \u6808\u662f\u7a7a\u7684 []\\ncustomStack.push(1);                          // \u6808\u53d8\u4e3a [1]\\ncustomStack.push(2);                          // \u6808\u53d8\u4e3a [1, 2]\\ncustomStack.pop();                            // \u8fd4\u56de 2 --&gt; \u8fd4\u56de\u6808\u9876\u503c 2\uff0c\u6808\u53d8\u4e3a [1]\\ncustomStack.push(2);                          // \u6808\u53d8\u4e3a [1, 2]\\ncustomStack.push(3);                          // \u6808\u53d8\u4e3a [1, 2, 3]\\ncustomStack.push(4);                          // \u6808\u4ecd\u7136\u662f [1, 2, 3]\uff0c\u4e0d\u80fd\u6dfb\u52a0\u5176\u4ed6\u5143\u7d20\u4f7f\u6808\u5927\u5c0f\u53d8\u4e3a 4\\ncustomStack.increment(5, 100);                // \u6808\u53d8\u4e3a [101, 102, 103]\\ncustomStack.increment(2, 100);                // \u6808\u53d8\u4e3a [201, 202, 103]\\ncustomStack.pop();                            // \u8fd4\u56de 103 --&gt; \u8fd4\u56de\u6808\u9876\u503c 103\uff0c\u6808\u53d8\u4e3a [201, 202]\\ncustomStack.pop();                            // \u8fd4\u56de 202 --&gt; \u8fd4\u56de\u6808\u9876\u503c 202\uff0c\u6808\u53d8\u4e3a [201]\\ncustomStack.pop();                            // \u8fd4\u56de 201 --&gt; \u8fd4\u56de\u6808\u9876\u503c 201\uff0c\u6808\u53d8\u4e3a []\\ncustomStack.pop();                            // \u8fd4\u56de -1 --&gt; \u6808\u4e3a\u7a7a\uff0c\u8fd4\u56de -1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= maxSize &lt;= 1000</code></li>\\n\\t<li><code>1 &lt;= x &lt;= 1000</code></li>\\n\\t<li><code>1 &lt;= k &lt;= 1000</code></li>\\n\\t<li><code>0 &lt;= val &lt;= 100</code></li>\\n\\t<li>\u6bcf\u79cd\u65b9\u6cd5 <code>increment</code>\uff0c<code>push</code> \u4ee5\u53ca <code>pop</code> \u5206\u522b\u6700\u591a\u8c03\u7528 <code>1000</code> \u6b21</li>\\n</ul>\\n","title":"1381. \u8bbe\u8ba1\u4e00\u4e2a\u652f\u6301\u589e\u91cf\u64cd\u4f5c\u7684\u6808","relatedTags":["\u6808","\u8bbe\u8ba1"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1381"}')}}]);